# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
pubsub_publisher = pubsub_v1.PublisherClient()

# Configuration from environment variables
PROJECT_ID = os.environ.get("GCP_PROJECT", os.environ.get("GOOGLE_CLOUD_PROJECT", ""))
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-events")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")
ALLOWED_EXTENSIONS = os.environ.get("ALLOWED_EXTENSIONS", ".csv,.json,.txt,.xml").split(",")
MAX_FILE_SIZE_MB = int(os.environ.get("MAX_FILE_SIZE_MB", "100"))


def process_file_from_gcs(event, context):
    """
    Cloud Function triggered by Cloud Storage events.
    Processes the uploaded file, writes metadata to Firestore,
    and publishes a notification to Pub/Sub.

    NOTE ON PERMISSIONS / SERVICE ACCOUNT SETUP:
    -----------------------------------------------------------
    For MVP/development, this function uses a service account with broad roles:
      - roles/storage.admin
      - roles/datastore.user
      - roles/pubsub.publisher

    *** THIS IS NOT RECOMMENDED FOR PRODUCTION. ***

    For production, follow the principle of least privilege:
      - Replace roles/storage.admin with roles/storage.objectViewer
        (or roles/storage.objectAdmin only if writing is needed)
      - Replace roles/datastore.user with a custom role granting only
        the specific Firestore operations needed (e.g., datastore.entities.create,
        datastore.entities.get)
      - roles/pubsub.publisher is already scoped; keep it.
      - Restrict resource-level IAM bindings to specific buckets, topics,
        and Firestore databases rather than project-wide grants.
      - Use separate service accounts per function if multiple functions exist.

    Setup commands for MVP (replace with least-privilege for production):
        export SA_NAME="file-processor-sa"
        export PROJECT_ID="your-project-id"

        gcloud iam service-accounts create $SA_NAME \
            --display-name="File Processor Cloud Function SA"

        gcloud projects add-iam-policy-binding $PROJECT_ID \
            --member="serviceAccount:${SA_NAME}@${PROJECT_ID}.iam.gserviceaccount.com" \
            --role="roles/storage.admin"

        gcloud projects add-iam-policy-binding $PROJECT_ID \
            --member="serviceAccount:${SA_NAME}@${PROJECT_ID}.iam.gserviceaccount.com" \
            --role="roles/datastore.user"

        gcloud projects add-iam-policy-binding $PROJECT_ID \
            --member="serviceAccount:${SA_NAME}@${PROJECT_ID}.iam.gserviceaccount.com" \
            --role="roles/pubsub.publisher"

        gcloud functions deploy process_file_from_gcs \
            --runtime python311 \
            --trigger-resource your-bucket-name \
            --trigger-event google.storage.object.finalize \
            --service-account "${SA_NAME}@${PROJECT_ID}.iam.gserviceaccount.com" \
            --set-env-vars "GCP_PROJECT=${PROJECT_ID},PUBSUB_TOPIC=file-processing-events,FIRESTORE_COLLECTION=processed_files"
    -----------------------------------------------------------

    Args:
        event (dict): Event payload containing Cloud Storage object metadata.
        context (google.cloud.functions.Context): Event metadata (event ID, timestamp, etc.).
    """
    bucket_name = event.get("bucket")
    file_name = event.get("name")
    file_size = int(event.get("size", 0))
    content_type = event.get("contentType", "unknown")
    metageneration = event.get("metageneration")
    time_created = event.get("timeCreated")
    event_id = context.event_id if context else "unknown"
    event_timestamp = context.timestamp if context else datetime.utcnow().isoformat()

    logger.info(
        f"Processing file: gs://{bucket_name}/{file_name} "
        f"(size={file_size}, type={content_type}, event_id={event_id})"
    )

    # --- Input Validation ---
    if not bucket_name or not file_name:
        logger.error("Missing bucket name or file name in event payload.")
        return {"status": "error", "message": "Invalid event payload"}

    file_extension = os.path.splitext(file_name)[1].lower()
    if ALLOWED_EXTENSIONS and file_extension not in ALLOWED_EXTENSIONS:
        logger.warning(
            f"Skipping file with disallowed extension: {file_name} "
            f"(allowed: {ALLOWED_EXTENSIONS})"
        )
        return {"status": "skipped", "message": f"File extension {file_extension} not allowed"}

    max_size_bytes = MAX_FILE_SIZE_MB * 1024 * 1024
    if file_size > max_size_bytes:
        logger.warning(
            f"Skipping oversized file: {file_name} "
            f"({file_size} bytes > {max_size_bytes} bytes limit)"
        )
        return {"status": "skipped", "message": "File exceeds size limit"}

    processing_result = {
        "status": "pending",
        "bucket": bucket_name,
        "file_name": file_name,
        "file_size": file_size,
        "content_type": content_type,
        "file_extension": file_extension,
        "event_id": event_id,
        "event_timestamp": event_timestamp,
    }

    try:
        # --- Step 1: Read and process the file from Cloud Storage ---
        file_metadata = _read_and_process_file(bucket_name, file_name, content_type)
        processing_result["file_metadata"] = file_metadata
        processing_result["status"] = "processed"
        logger.info(f"Successfully read file: {file_name}")

    except Exception as e:
        logger.error(f"Error reading file gs://{bucket_name}/{file_name}: {e}", exc_info=True)
        processing_result["status"] = "error"
        processing_result["error_message"] = str(e)

    try:
        # --- Step 2: Write processing record to Firestore ---
        doc_id = _write_to_firestore(processing_result)
        processing_result["firestore_doc_id"] = doc_id
        logger.info(f"Written to Firestore: collection={FIRESTORE_COLLECTION}, doc_id={doc_id}")

    except Exception as e:
        logger.error(f"Error writing to Firestore: {e}", exc_info=True)
        processing_result["firestore_error"] = str(e)

    try:
        # --- Step 3: Publish event to Pub/Sub ---
        message_id = _publish_to_pubsub(processing_result)
        processing_result["pubsub_message_id"] = message_id
        logger.info(f"Published to Pub/Sub topic={PUBSUB_TOPIC}, message_id={message_id}")

    except Exception as e:
        logger.error(f"Error publishing to Pub/Sub: {e}", exc_info=True)
        processing_result["pubsub_error"] = str(e)

    logger.info(f"Completed processing for {file_name}: status={processing_result['status']}")
    return processing_result


def _read_and_process_file(bucket_name, file_name, content_type):
    """
    Reads a file from Cloud Storage and extracts metadata / content summary.

    Returns:
        dict: Extracted metadata about the file contents.
    """
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    # Get blob metadata
    blob.reload()
    metadata = {
        "md5_hash": blob.md5_hash,
        "crc32c": blob.crc32c,
        "storage_class": blob.storage_class,
        "time_created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "custom_metadata": blob.metadata or {},
    }

    # Read content for supported text-based types (limit to first 1MB for processing)
    max_preview_bytes = 1 * 1024 * 1024
    if content_type and ("text" in content_type or "json" in content_type or "csv" in content_type):
        content_bytes = blob.download_as_bytes(start=0, end=max_preview_bytes)
        content_text = content_bytes.decode("utf-8", errors="replace")
        line_count = content_text.count("\n") + 1
        metadata["preview_line_count"] = line_count
        metadata["preview_char_count"] = len(content_text)
        metadata["first_line"] = content_text.split("\n")[0][:500] if content_text else ""

        # If JSON, validate structure
        if "json" in content_type or file_name.endswith(".json"):
            try:
                parsed = json.loads(content_text)
                if isinstance(parsed, list):
                    metadata["json_type"] = "array"
                    metadata["json_array_length"] = len(parsed)
                elif isinstance(parsed, dict):
                    metadata["json_type"] = "object"
                    metadata["json_top_level_keys"] = list(parsed.keys())[:50]
            except json.JSONDecodeError as e:
                metadata["json_parse_error"] = str(e)

    return metadata


def _write_to_firestore(processing_result):
    """
    Writes the processing result to a Firestore document.

    Returns:
        str: The Firestore document ID.
    """
    collection_ref = firestore_client.collection(FIRESTORE_COLLECTION)

    doc_data = {
        **processing_result,
        "written_at": firestore.SERVER_TIMESTAMP,
        "ttl_expiry": datetime.utcnow().isoformat(),  # Could be used for TTL policies
    }

    # Remove any non-serializable items
    doc_data = _sanitize_for_firestore(doc_data)

    # Use event_id as document ID for idempotency
    doc_id = processing_result.get("event_id", None)
    if doc_id and doc_id != "unknown":
        doc_ref = collection_ref.document(doc_id)
        doc_ref.set(doc_data, merge=True)
        return doc_id
    else:
        # Auto-generate document ID
        _, doc_ref = collection_ref.add(doc_data)
        return doc_ref.id


def _sanitize_for_firestore(data):
    """
    Recursively sanitize data for Firestore compatibility.
    Firestore doesn't support certain types directly.
    """
    if isinstance(data, dict):
        return {k: _sanitize_for_firestore(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [_sanitize_for_firestore(item) for item in data]
    elif isinstance(data, (str, int, float, bool, type(None))):
        return data
    elif isinstance(data, datetime):
        return data.isoformat()
    else:
        return str(data)


def _publish_to_pubsub(processing_result):
    """
    Publishes the processing result as a message to a Pub/Sub topic.

    Returns:
        str: The published message ID.
    """
    topic_path = pubsub_publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    message_body = {
        "event_type": "file_processed",
        "status": processing_result.get("status"),
        "bucket": processing_result.get("bucket"),
        "file_name": processing_result.get("file_name"),
        "file_size": processing_result.get("file_size"),
        "content_type": processing_result.get("content_type"),
        "event_id": processing_result.get("event_id"),
        "event_timestamp": processing_result.get("event_timestamp"),
        "firestore_doc_id": processing_result.get("firestore_doc_id"),
        "published_at": datetime.utcnow().isoformat(),
    }

    if processing_result.get("error_message"):
        message_body["error_message"] = processing_result["error_message"]

    message_bytes = json.dumps(message_body, default=str).encode("utf-8")

    # Add attributes for Pub/Sub filtering
    attributes = {
        "status": processing_result.get("status", "unknown"),
        "content_type": processing_result.get("content_type", "unknown"),
        "bucket": processing_result.get("bucket", "unknown"),
    }

    future = pubsub_publisher.publish(topic_path, data=message_bytes, **attributes)
    message_id = future.result(timeout=30)

    return message_id


